import React, { useRef, useEffect, useState } from "react";
import { Routes, Route, useParams, useNavigate } from "react-router-dom";
import { io } from "socket.io-client";

// 🏠 HOME PAGE (enter room)
function Home() {
  const [room, setRoom] = useState("");
  const navigate = useNavigate();

  return (
    <div style={{ textAlign: "center", marginTop: "100px" }}>
      <h2>Join Whiteboard</h2>

      <input
        placeholder="Enter Room ID"
        value={room}
        onChange={(e) => setRoom(e.target.value)}
      />

      <button onClick={() => navigate("/room/" + room)}>
        Join
      </button>
    </div>
  );
}

// 🎨 WHITEBOARD PAGE
function Whiteboard() {
  const { roomId } = useParams();

  const canvasRef = useRef(null);
  const drawing = useRef(false);
  const socketRef = useRef(null);

  const [color, setColor] = useState("#000000");
  const [tool, setTool] = useState("pen");
  const [brushSize, setBrushSize] = useState(2);

  // 🔌 Connect socket
  useEffect(() => {
    socketRef.current = io("http://localhost:5006", {
      query: { room: roomId },
    });

    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");

    socketRef.current.on("draw", (data) => {
      drawLine(ctx, data);
    });

    socketRef.current.on("clear", () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
    });

    return () => socketRef.current.disconnect();
  }, [roomId]);

  // 🖊 Start/Stop drawing
  const startDrawing = () => (drawing.current = true);

  const stopDrawing = () => {
    drawing.current = false;
    const ctx = canvasRef.current.getContext("2d");
    ctx.beginPath();
  };

  // ✏️ Draw
  const draw = (e) => {
    if (!drawing.current) return;

    const rect = canvasRef.current.getBoundingClientRect();

    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    const data = {
      x,
      y,
      color,
      tool,
      size: brushSize,
    };

    drawLine(canvasRef.current.getContext("2d"), data);
    socketRef.current.emit("draw", data);
  };

  // 🎨 Drawing logic
  const drawLine = (ctx, { x, y, color, tool, size }) => {
    if (tool === "eraser") {
      ctx.globalCompositeOperation = "destination-out";
    } else {
      ctx.globalCompositeOperation = "source-over";
      ctx.strokeStyle = color;
    }

    ctx.lineWidth = size;
    ctx.lineTo(x, y);
    ctx.stroke();
    ctx.beginPath();
    ctx.moveTo(x, y);
  };

  // 🧹 Clear
  const clearCanvas = () => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");

    ctx.clearRect(0, 0, canvas.width, canvas.height);
    socketRef.current.emit("clear");
  };

  // 💾 Download
  const downloadImage = () => {
    const canvas = canvasRef.current;
    const link = document.createElement("a");
    link.download = "whiteboard.png";
    link.href = canvas.toDataURL();
    link.click();
  };

  // 📱 Touch support
  const handleTouchMove = (e) => {
    const touch = e.touches[0];
    draw({
      clientX: touch.clientX,
      clientY: touch.clientY,
    });
  };

  return (
    <div style={{ textAlign: "center" }}>
      <h3>Room: {roomId}</h3>

      {/* 🎨 Color */}
      <input
        type="color"
        value={color}
        onChange={(e) => setColor(e.target.value)}
      />

      {/* Tools */}
      <button onClick={() => setTool("pen")}>Pen</button>
      <button onClick={() => setTool("eraser")}>Eraser</button>

      {/* Brush */}
      <div>
        Size: {brushSize}
        <input
          type="range"
          min="1"
          max="30"
          value={brushSize}
          onChange={(e) => setBrushSize(Number(e.target.value))}
        />
      </div>

      {/* Actions */}
      <button onClick={clearCanvas}>Clear</button>
      <button onClick={downloadImage}>Download</button>

      <br /><br />

      <canvas
        ref={canvasRef}
        width={800}
        height={500}
        style={{ border: "2px solid black" }}
        onMouseDown={startDrawing}
        onMouseUp={stopDrawing}
        onMouseMove={draw}
        onTouchStart={startDrawing}
        onTouchEnd={stopDrawing}
        onTouchMove={handleTouchMove}
      />
    </div>
  );
}

// 🔀 ROUTES
function App() {
  return (
    <Routes>
      <Route path="/" element={<Home />} />
      <Route path="/room/:roomId" element={<Whiteboard />} />
    </Routes>
  );
}

export default App;
